mapper.select:
select id, voice, name, types, status, create_user, create_dept, create_time, update_user,
       update_time, is_deleted, level, text, isopen, is_send, send_user, is_receive
from a_alert_info

    is_deleted = #{isDeleted}
    and name = #{name}
    and types = #{types}
    and level = #{level}
    and isopen = #{isopen}
    and is_send = #{isSend}
    and is_receive = #{isReceive}
    and status = #{status}

order by types desc, id desc
